from scipy.stats import chi2_contingency
def task_func(data, col1, col2):
    if data.empty:
        raise ValueError("If 'data' is empty")
    if col1 not in data.columns or col2 not in data.columns:
        raise ValueError("If 'col1' or 'col2' are not in 'data'")
    if not pd.api.types.is_categorical_dtype(data[col1]) and not data[col1].dtype.name == 'category':
        if not np.issubdtype(data[col1].dtype, np.number):
            try:
                data[col1] = data[col1].astype('category')
            except:
                raise TypeError("If one or both of the columns contain non-categorical data")
        else:
            raise TypeError("If one or both of the columns contain non-categorical data")
    if not pd.api.types.is_categorical_dtype(data[col2]) and not data[col2].dtype.name == 'category':
        if not np.issubdtype(data[col2].dtype, np.number):
            try:
                data[col2] = data[col2].astype('category')
            except:
                raise TypeError("If one or both of the columns contain non-categorical data")
        else:
            raise TypeError("If one or both of the columns contain non-categorical data")
    if data[col1].nunique() < 2:
        raise ValueError("if one or both of the columns do not have multiple categories")
    if data[col2].nunique() < 2:
        raise ValueError("if one or both of the columns do not have multiple categories")
    contingency_table = pd.crosstab(data[col1], data[col2])
    chi2, p_value, dof, expected = chi2_contingency(contingency_table)
    if (expected < 5).any():
        raise ValueError("if some categories have less than 5 observations (violating the chi-square test assumptions)")
    return p_value

