def task_func(array1, array2):
    if len(array1) != len(array2):
        raise ValueError("If the input arrays have different lengths.")

    if len(array1) == 0:
        return 0.0

    points = np.array([(x, y) for x, y in zip(array1, array2)])

    max_distance = 0.0
    for i in range(len(points)):
