import random
import re
def task_func(text, seed=None):
    if seed is not None:
        random.seed(seed)

    def scramble_word(word):
        if len(word) <= 3:
            return word
        middle = list(word[1:-1])
        random.shuffle(middle)
        return word[0] + ''.join(middle) + word[-1]

    def scramble_match(match):
        return scramble_word(match.group())

    return re.sub(r'\b\w+\b', scramble_match, text)

