from glob import glob
def task_func(src_folder, dst_folder):
    failed_files = []
    success = True
    message = ""

    # Ensure source folder exists
    if not os.path.exists(src_folder):
        return {'success': False, 'message': f"Source folder {src_folder} does not exist.", 'failed_files': []}

    # Ensure destination folder exists, create if it doesn't
    os.makedirs(dst_folder, exist_ok=True)

    # Get all files in the source folder (exclude directories)
    files = [f for f in glob(os.path.join(src_folder, "*")) if os.path.isfile(f)]

    if not files:
        return {'success': True, 'message': "No files to compress.", 'failed_files': []}

    # Process each file
    for file_path in files:
        filename = os.path.basename(file_path)
        dest_path = os.path.join(dst_folder, filename + ".gz")

        try:
            # Use gzip to compress the file
            result = subprocess.run(
                ['gzip', file_path],
                capture_output=True,
                text=True
            )
            if result.returncode != 0:
                raise Exception(result.stderr)

            # Move the compressed file (gzip creates filename.gz)
            compressed_file = file_path + ".gz"
            shutil.move(compressed_file, dest_path)

        except Exception as e:
            failed_files.append(filename)
            success = False

    # Generate message
    if success:
        message = f"Successfully compressed and moved {len(files)} files."
    else:
        message = f"Partially completed: {len(files) - len(failed_files)} files compressed and moved, {len(failed_files)} failed."

    return {'success': success, 'message': message, 'failed_files': failed_files}

