def task_func(url='http://example.com'):
    try:
        response = requests.get(url)
        response.raise_for_status()
    except requests.ConnectionError as e:
        raise ConnectionError("Failed to connect to the URL.") from e
    except requests.HTTPError as e:
        raise requests.HTTPError("HTTP request failed.") from e

    try:
        soup = BeautifulSoup(response.content, 'html.parser')
        table = soup.find('table')
        if not table:
            raise ValueError("No table found on the page.")

        headers = [th.get_text(strip=True) for th in table.find_all('th')]
        if not headers:
            first_row = table.find_all('tr')[0]
            headers = [f"Column_{i}" for i in range(len(first_row.find_all(['td', 'th'])))]

        data = []
        for row in table.find_all('tr'):
            cells = row.find_all(['td', 'th'])
            row_data = [cell.get_text(strip=True) for cell in cells]
            if row_data:
                data.append(row_data)

        if not data:
            raise ValueError("No table data found.")

        df = pd.DataFrame(data, columns=headers)
        return df
    except Exception as e:
        raise ValueError("Page content could not be parsed.") from e

