    if not os.path.exists(file_path):
        raise ValueError(f"File {file_path} does not exist.")

    with open(file_path, 'r') as file:
        data = json.load(file)

    if not isinstance(data, dict):
        raise ValueError("JSON root must be an object.")

    required_fields = INPUT_JSON["required"]
    for field in required_fields:
        if field not in data:
            raise ValueError(f"Missing required field: {field}")

    for field, field_info in INPUT_JSON["properties"].items():
        field_type = field_info["type"]
        if field in data:
            if not isinstance(data[field], field_type):
                raise ValueError(f"Field '{field}' must be of type {field_type.__name__}.")
        else:
            if field in required_fields:
                raise ValueError(f"Missing required field: {field}")

    if "email" in data:
        if not re.match(EMAIL_REGEX, data["email"]):
            raise ValueError("Invalid email format.")

    if attribute not in data:
        raise ValueError(f"Attribute '{attribute}' not found in JSON.")

    return data[attribute]

