import pandas as pd
import random
def task_func(data, columns=['Name', 'Age', 'Occupation'], fill_missing=False, num_range=(0, 100), seed=None):
    if seed is not None:
        random.seed(seed)

    processed_data = []
    for row in data:
        new_row = [None] * len(columns)
        for i, val in enumerate(row):
            if i < len(columns):
                new_row[i] = val
        processed_data.append(new_row)

    df = pd.DataFrame(processed_data, columns=columns)

    if fill_missing:
        for col in df.columns:
            if df[col].dtype in ['int64', 'float64', 'int32', 'float32']:
                nan_mask = df[col].isna()
                random_values = [random.uniform(num_range[0], num_range[1]) for _ in range(nan_mask.sum())]
                df.loc[nan_mask, col] = random_values

    return df

